fn solve(landStartTime: Vec<i64>, landDuration: Vec<i64>, waterStartTime: Vec<i64>, waterDuration: Vec<i64>) -> i64 {
    let n = landStartTime.len();
    let m = waterStartTime.len();

    // Precompute all possible end times for land and water attractions
    let mut land_end_times = vec![0; n];
    let mut water_end_times = vec![0; m];

    for i in 0..n {
        land_end_times[i] = landStartTime[i] + landDuration[i];
    }

    for j in 0..m {
        water_end_times[j] = waterStartTime[j] + waterDuration[j];
    }

    // Try all combinations of one land and one water attraction
    let mut min_time = i64::MAX;

    for i in 0..n {
        for j in 0..m {
            // Case 1: Land first, then water
            let land_end = land_end_times[i];
            let water_start = waterStartTime[j];
            let water_end = water_end_times[j];

            // The water can start as soon as it's open, which is max(land_end, water_start)
            let water_start_time = std::cmp::max(land_end, water_start);
            let total_time = water_start_time + waterDuration[j];
            min_time = std::cmp::min(min_time, total_time);

            // Case 2: Water first, then land
            let water_end = water_end_times[j];
            let land_start = landStartTime[i];
            let land_end = land_end_times[i];

            // The land can start as soon as it's open, which is max(water_end, land_start)
            let land_start_time = std::cmp::max(water_end, land_start);
            let total_time = land_start_time + landDuration[i];
            min_time = std::cmp::min(min_time, total_time);
        }
    }

    min_time
}
