fn solve(landStartTime: Vec<i64>, landDuration: Vec<i64>, waterStartTime: Vec<i64>, waterDuration: Vec<i64>) -> i64 {
    let n = landStartTime.len();
    let m = waterStartTime.len();

    // Precompute all possible end times for land and water attractions
    let mut land_end_times = Vec::new();
    for i in 0..n {
        let start = landStartTime[i];
        let duration = landDuration[i];
        land_end_times.push(start + duration);
    }

    let mut water_end_times = Vec::new();
    for j in 0..m {
        let start = waterStartTime[j];
        let duration = waterDuration[j];
        water_end_times.push(start + duration);
    }

    // Calculate the earliest possible end time for each combination of land and water attractions
    let mut min_time = i64::MAX;

    for i in 0..n {
        for j in 0..m {
            // Land first then water
            let land_end = land_end_times[i];
            let water_start = waterStartTime[j];
            let water_end = water_end_times[j];
            let time_land_water = std::cmp::max(land_end, water_start) + waterDuration[j];
            min_time = std::cmp::min(min_time, time_land_water);

            // Water first then land
            let water_end = water_end_times[j];
            let land_start = landStartTime[i];
            let land_end = land_end_times[i];
            let time_water_land = std::cmp::max(water_end, land_start) + landDuration[i];
            min_time = std::cmp::min(min_time, time_water_land);
        }
    }

    min_time
}
